features.snippet:
assign apu_rvalid = apu_active_q && (cnt_q == '0);
assign apu_stall = apu_active_q && !(apu_rvalid && id_ready);
assign id_ready = !apu_stall;

logic [4:0] cnt_q;
assign apu_rvalid = apu_active_q && (cnt_q == '0);
assign done = apu_rvalid && id_ready;
always_ff @(posedge clk) if (apu_active_q && cnt_q > 0) cnt_q <= cnt_q - 1;
